#[Table('tenant_integrations', keyType: 'string')]
#[Fillable('tenant_id', 'provider', 'config', 'status')]
#[Hidden('config')]
final class TenantIntegration extends Model implements TenantIntegrationInterface
{
    use HasFactory;
    use HasUlids;
    use BelongsToTenant;
    use HasMetadata;
    use HasUserstamps;
    use HasAuditable;
    use SoftDeletes;

    protected function casts(): array
    {
        return ['config' => IntegrationConfig::class];
    }
}
